export const ROUTE_MANIFEST_BY_PATH: ReadonlyMap<string, RouteManifestEntry> = new Map(
  ROUTE_MANIFEST.map((entry) => [entry.path, entry as RouteManifestEntry]),
);

export function getRouteManifestEntry(pathname: string) {
  const normalized = pathname === "/" ? "/" : `/${pathname.replace(/^\/+/, "").replace(/\/+$/, "")}`;
  return ROUTE_MANIFEST_BY_PATH.get(normalized || "/");
}

export function getCanonicalUrl(entry: RouteManifestEntry) {
  return `${SITE_ORIGIN}${entry.canonicalPath === "/" ? "" : entry.canonicalPath}`;
}
